import { guardProcessEnv } from "./helpers/env-guard.js";
guardProcessEnv();

import { afterAll, beforeEach, describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";

const tmpRoot = fs.mkdtempSync(path.join(os.tmpdir(), "bobbit-session-recovery-agent-dir-"));
const projectRoot = path.join(tmpRoot, "project");
const tmpHome = path.join(tmpRoot, "home");
const activeAgentDir = path.join(tmpRoot, "active-agent");
const historicalAgentDir = path.join(tmpRoot, "historical-agent");
const previousEnv = {
	BOBBIT_AGENT_DIR: process.env.BOBBIT_AGENT_DIR,
	BOBBIT_DIR: process.env.BOBBIT_DIR,
	HOME: process.env.HOME,
	USERPROFILE: process.env.USERPROFILE,
};

const bobbitDirModule = await import("../../src/server/bobbit-dir.ts");
const previousProjectRoot = bobbitDirModule.getProjectRoot();
const { SessionManager, switchSessionPathForAgent } = await import("../../src/server/agent/session-manager.ts");
const { formatAgentTimestamp, slugifyCwd } = await import("../../src/server/agent/agent-session-path.ts");

// Re-assert the environment and startup-pinned agent-dir state before every
// test. With isolate:false, sibling files reset the shared agent-dir singleton;
// per-test setup makes this suite independent of collection and hook ordering.
beforeEach(async () => {
	fs.mkdirSync(projectRoot, { recursive: true });
	fs.mkdirSync(tmpHome, { recursive: true });
	fs.mkdirSync(sessionsRoot(activeAgentDir), { recursive: true });
	fs.mkdirSync(sessionsRoot(historicalAgentDir), { recursive: true });
	process.env.BOBBIT_AGENT_DIR = activeAgentDir;
	process.env.BOBBIT_DIR = path.join(tmpRoot, ".bobbit");
	process.env.HOME = tmpHome;
	process.env.USERPROFILE = tmpHome;
	bobbitDirModule.setProjectRoot(projectRoot);
	bobbitDirModule.resetAgentDirStateForTests();
	bobbitDirModule.initializeAgentDirRuntime({
		env: process.env,
		projectRoot,
		stateDir: path.join(tmpRoot, ".bobbit", "state"),
	});
	await recordHistoryIfAvailable(historicalAgentDir);
});

const managers: any[] = [];

function cleanupManager(manager: any): void {
	if (manager._statusHeartbeatTimer) {
		clearInterval(manager._statusHeartbeatTimer);
		manager._statusHeartbeatTimer = null;
	}
	manager.sessionsWithConnectedClients?.clear();
	manager.sessions?.clear();
}

function makeManager(store?: any): any {
	const manager: any = new SessionManager();
	manager._testStore = store ?? makeStore();
	managers.push(manager);
	return manager;
}

function makeStore(initial: any[] = []): any {
	const records = new Map<string, any>();
	for (const record of initial) records.set(record.id, record);
	return {
		get: (id: string) => records.get(id),
		put: (record: any) => { records.set(record.id, record); },
		update: (id: string, fields: any) => { records.set(id, { ...records.get(id), ...fields }); },
		archive: (id: string) => { const existing = records.get(id); if (existing) records.set(id, { ...existing, archived: true }); },
		purge: (id: string) => records.delete(id),
		getAll: () => [...records.values()],
	};
}

function sessionsRoot(agentDir: string): string {
	return path.join(agentDir, "sessions");
}

function transcriptPath(agentDir: string, cwd: string, createdAt: number, id: string): string {
	return path.join(
		sessionsRoot(agentDir),
		`--${slugifyCwd(cwd)}--`,
		`${formatAgentTimestamp(createdAt)}_${id}.jsonl`,
	).replace(/\\/g, "/");
}

function writeRecoverableTranscript(agentDir: string, opts: { cwd: string; createdAt: number; id: string; text?: string }): string {
	const file = transcriptPath(agentDir, opts.cwd, opts.createdAt, opts.id);
	fs.mkdirSync(path.dirname(file), { recursive: true });
	fs.writeFileSync(
		file,
		JSON.stringify({ type: "message", message: { role: "user", content: opts.text ?? opts.id } }) + "\n",
		"utf-8",
	);
	return file;
}

function makePersistedSession(overrides: Record<string, any> = {}): any {
	return {
		id: overrides.id ?? "session-under-test",
		title: "Recoverable session",
		cwd: overrides.cwd ?? projectRoot,
		agentSessionFile: overrides.agentSessionFile ?? "",
		createdAt: overrides.createdAt ?? Date.parse("2026-04-03T15:15:12.009Z"),
		lastActivity: overrides.lastActivity ?? Date.parse("2026-04-03T15:15:42.009Z"),
		...overrides,
	};
}

async function recordHistoryIfAvailable(agentDir: string): Promise<boolean> {
	const fn = (bobbitDirModule as any).recordAgentDirHistory;
	if (typeof fn !== "function") return false;
	await Promise.resolve(fn(agentDir));
	return true;
}

function assertHistoryRecorderAvailable(): void {
	assert.equal(
		typeof (bobbitDirModule as any).recordAgentDirHistory,
		"function",
		"recordAgentDirHistory(dir) must be exported so recoverSessionFile can scan historical sessions roots",
	);
}

function samePath(actual: string | null, expected: string): void {
	assert.equal(actual?.replace(/\\/g, "/"), expected.replace(/\\/g, "/"));
}

afterAll(() => {
	while (managers.length > 0) cleanupManager(managers.pop());
	for (const [key, value] of Object.entries(previousEnv)) {
		if (value === undefined) delete process.env[key];
		else process.env[key] = value;
	}
	bobbitDirModule.setProjectRoot(previousProjectRoot);
	bobbitDirModule.resetAgentDirStateForTests();
	fs.rmSync(tmpRoot, { recursive: true, force: true });
});

describe("recoverSessionFile with configurable agent directories", () => {
	it("recovers a missing agentSessionFile from the startup active sessions root", () => {
		const manager = makeManager();
		const ps = makePersistedSession({ id: "active-session" });
		const expected = writeRecoverableTranscript(activeAgentDir, ps);

		samePath(manager.recoverSessionFile(ps), expected);
	});

	it("recovers from a recorded historical sessions root after the active agent dir changes", () => {
		assertHistoryRecorderAvailable();
		const manager = makeManager();
		const ps = makePersistedSession({ id: "historical-session" });
		const expected = writeRecoverableTranscript(historicalAgentDir, ps);

		samePath(manager.recoverSessionFile(ps), expected);
	});

	it("recovers legacy ~/.bobbit/agent and ~/.pi/agent transcripts even when a custom active dir is configured", () => {
		const manager = makeManager();
		const legacyBobbitPs = makePersistedSession({ id: "legacy-bobbit-session", createdAt: Date.parse("2026-04-03T16:00:00.000Z") });
		const legacyPiPs = makePersistedSession({ id: "legacy-pi-session", createdAt: Date.parse("2026-04-03T17:00:00.000Z") });
		const legacyBobbit = writeRecoverableTranscript(path.join(tmpHome, ".bobbit", "agent"), legacyBobbitPs);
		const legacyPi = writeRecoverableTranscript(path.join(tmpHome, ".pi", "agent"), legacyPiPs);

		samePath(manager.recoverSessionFile(legacyBobbitPs), legacyBobbit);
		samePath(manager.recoverSessionFile(legacyPiPs), legacyPi);
	});

	it("keeps an exact persisted absolute agentSessionFile readable under a historical sessions root", async () => {
		const ps = makePersistedSession({ id: "persisted-historical-session", archived: true });
		const persistedPath = writeRecoverableTranscript(historicalAgentDir, { ...ps, text: "read me from the historical persisted absolute path" });
		ps.agentSessionFile = persistedPath;
		const store = makeStore([ps]);
		const manager = makeManager(store);

		const messages = await manager.getArchivedMessages(ps.id);
		assert.equal(messages.length, 1);
		assert.deepEqual(messages[0], { role: "user", content: "read me from the historical persisted absolute path" });
	});

	it("remaps sandbox switch_session paths from historical host transcripts to migrated active mounted transcripts", () => {
		const ps = makePersistedSession({
			id: "sandbox-migrated-transcript-session",
			cwd: "/workspace",
			sandboxed: true,
			projectId: "project-1",
			createdAt: Date.parse("2026-04-03T18:00:00.000Z"),
		});
		const oldPersistedPath = writeRecoverableTranscript(historicalAgentDir, { ...ps, text: "old copy remains authoritative for Bobbit reads" });
		const activeMigratedPath = writeRecoverableTranscript(activeAgentDir, { ...ps, text: "active mounted copy is visible to sandbox" });
		ps.agentSessionFile = oldPersistedPath;

		assert.equal(
			switchSessionPathForAgent(ps),
			"/home/node/.bobbit/agent/sessions/" + path.relative(sessionsRoot(activeAgentDir), activeMigratedPath).replace(/\\/g, "/"),
		);
		samePath(ps.agentSessionFile, oldPersistedPath);
	});

	it("leaves sandbox historical host transcripts unchanged when no active migrated copy exists", () => {
		const ps = makePersistedSession({
			id: "sandbox-not-migrated-transcript-session",
			cwd: "/workspace",
			sandboxed: true,
			projectId: "project-1",
			createdAt: Date.parse("2026-04-03T19:00:00.000Z"),
		});
		const oldPersistedPath = writeRecoverableTranscript(historicalAgentDir, ps);
		ps.agentSessionFile = oldPersistedPath;

		samePath(switchSessionPathForAgent(ps), oldPersistedPath);
	});

	it("keeps an exact persisted absolute agentSessionFile readable outside known sessions roots", async () => {
		const outside = path.join(tmpRoot, "outside-readable-transcript.jsonl");
		fs.writeFileSync(outside, JSON.stringify({ type: "message", message: { role: "user", content: "read from exact outside path" } }) + "\n", "utf-8");
		const ps = makePersistedSession({
			id: "outside-readable-session",
			archived: true,
			agentSessionFile: outside,
			createdAt: Date.parse("2036-04-03T15:15:12.009Z"),
		});
		const store = makeStore([ps]);
		const manager = makeManager(store);

		samePath(manager.recoverSessionFile(ps), outside);
		assert.deepEqual(await manager.getArchivedMessages(ps.id), [{ role: "user", content: "read from exact outside path" }]);
	});

	it("does not delete exact persisted outside transcript files during purge", async () => {
		const outside = path.join(tmpRoot, "outside-purge-readonly.jsonl");
		fs.writeFileSync(outside, JSON.stringify({ type: "message", message: { role: "user", content: "do not delete" } }) + "\n", "utf-8");
		fs.writeFileSync(outside.replace(/\.jsonl$/, ".bobbit.json"), JSON.stringify({ version: 1, bobbitSessionId: "outside-purge-session", agentSessionId: "agent", role: "general", title: "Outside", createdAt: Date.now() }), "utf-8");
		const ps = makePersistedSession({
			id: "outside-purge-session",
			archived: true,
			agentSessionFile: outside,
		});
		const store = makeStore([ps]);
		const manager = makeManager(store);

		assert.equal(await manager.purgeArchivedSession(ps.id), true);
		assert.equal(fs.existsSync(outside), true, "outside exact transcript must not be deleted by purge");
		assert.equal(fs.existsSync(outside.replace(/\.jsonl$/, ".bobbit.json")), true, "outside exact sidecar must not be deleted by purge");
	});

	it("rejects a corrupted persisted absolute agentSessionFile outside known sessions roots", async () => {
		const outside = path.join(tmpRoot, "arbitrary-outside-not-transcript.jsonl");
		fs.writeFileSync(outside, JSON.stringify({ hello: "world" }) + "\n", "utf-8");
		const ps = makePersistedSession({
			id: "corrupt-outside-session",
			archived: true,
			agentSessionFile: outside,
			createdAt: Date.parse("2036-04-03T15:15:12.009Z"),
		});
		const store = makeStore([ps]);
		const manager = makeManager(store);

		assert.equal(manager.recoverSessionFile(ps), null);
		assert.deepEqual(await manager.getArchivedMessages(ps.id), []);
	});
});
